const decision = $('Webhook1').first().json.query.decision;
const sendDateStr = $input.first().json.Date;

// parse DD-MM-YYYY
const [day, month, year] = sendDateStr.split('-');
const sendDate = new Date(year, month - 1, day);

// normalize today
const today = new Date();
today.setHours(0, 0, 0, 0);
sendDate.setHours(0, 0, 0, 0);

// calculate gap in days
const diffDays = Math.abs((today - sendDate) / (1000 * 60 * 60 * 24));



if (diffDays>=10)
  var output = "timeout";
else if( decision === "accepted")
  output = "accepted"
else 
  output = "rejected"

// final result
return [
  {
    json: {
      result: output
    }
  }
];
